module top_module(output reg [7:0] inverted_out, input [7:0] in, input ld,rshct,clk,reset);always @(posedge clk, posedge reset)
begin
    if(reset)
        inverted_out <= 0;
    else if(ld)
        inverted_out <= in;
    else if(rshct)
        inverted_out <= inverted_out >> 1;
end
endmodule
